def validate_campaign_structure(campaigns: list) -> dict:
    """Validate M3 swim lane architecture and audience exclusions."""
    issues = []

    lanes = {"prospecting": [], "retargeting": [], "retention": []}

    for campaign in campaigns:
        lane = campaign.get("lane", "").lower()
        if lane in lanes:
            lanes[lane].append(campaign)
        else:
            issues.append(f"Campaign {campaign['name']} missing lane classification")

    # Check exclusions
    for pros_campaign in lanes["prospecting"]:
        if not pros_campaign.get("excludes_retargeting"):
            issues.append(f"Prospecting campaign {pros_campaign['name']} missing retargeting exclusion")
        if not pros_campaign.get("excludes_retention"):
            issues.append(f"Prospecting campaign {pros_campaign['name']} missing retention exclusion")

    for retarg_campaign in lanes["retargeting"]:
        if not retarg_campaign.get("excludes_retention"):
            issues.append(f"Retargeting campaign {retarg_campaign['name']} missing retention exclusion")

    return {
        "passed": len(issues) == 0,
        "lane_counts": {k: len(v) for k, v in lanes.items()},
        "issues": issues
    }

def validate_creative_concept_diversity(creatives: list) -> dict:
    """Check if creatives are distinct concepts or just variations."""
    issues = []

    hooks = [c.get("hook", "") for c in creatives]
    mechanisms = [c.get("mechanism", "") for c in creatives]

    # Simple similarity check (would use embeddings in production)
    unique_hooks = len(set(hooks))
    unique_mechanisms = len(set(mechanisms))

    diversity_ratio = (unique_hooks + unique_mechanisms) / (len(creatives) * 2)

    if diversity_ratio < 0.7:
        issues.append(f"Low concept diversity ({diversity_ratio:.1%}) - likely testing variations not concepts")

    # Check for duplicate hooks
    hook_counts = {}
    for hook in hooks:
        hook_counts[hook] = hook_counts.get(hook, 0) + 1

    for hook, count in hook_counts.items():
        if count > 1:
            issues.append(f"Duplicate hook detected: '{hook}' appears {count} times")

    return {
        "passed": len(issues) == 0,
        "diversity_ratio": diversity_ratio,
        "unique_hooks": unique_hooks,
        "unique_mechanisms": unique_mechanisms,
        "issues": issues
    }

def detect_creative_fatigue(creative_id: str, metrics_timeline: list) -> dict: """Detect creative fatigue from Hook Rate decline and frequency spike.""" if len(metrics_timeline) < 2: return {"passed": True, "status": "insufficient_data"}
first_week = metrics_timeline[0] latest_week = metrics_timeline[-1]
hook_rate_decline = ((first_week["hook_rate"] - latest_week["hook_rate"]) / first_week["hook_rate"]) * 100 frequency = latest_week["frequency"] cpa_increase = ((latest_week["cpa"] - first_week["cpa"]) / first_week["cpa"]) * 100
fatigue_signals = []
if hook_rate_decline > 30: fatigue_signals.append(f"Hook Rate declined {hook_rate_decline:.1f}% (>30% threshold)")
if frequency > 3.5: fatigue_signals.append(f"Frequency at {frequency:.1f} (>3.5 threshold)")
if cpa_increase > 40: fatigue_signals.append(f"CPA increased {cpa_increase:.1f}% (>40% threshold)")
is_fatigued = len(fatigue_signals) >= 2
return { "passed": not is_fatigued, "creative_id": creative_id, "status": "fatigued" if is_fatigued else "healthy", "hook_rate_decline_pct": round(hook_rate_decline, 1), "frequency": frequency, "cpa_increase_pct": round(cpa_increase, 1), "signals": fatigue_signals, "recommendation": "Ship replacement concept within 24h" if is_fatigued else "Continue monitoring" }
